request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?elem ?name ?type WHERE {
  ?model a bboExt:Model .
  FILTER(CONTAINS(STR(?model), "1dccc40d34ef40f9b36123e2fbca1a63"))
  ?elem a ?type .
  ?elem bbo:name ?name .
  FILTER(?type = bboExt:Model || ?type = bboExt:Definitions || ?type = bboExt:Choreography)
  {
    BIND(?model AS ?elem)
  }
  UNION
  {
    ?elem tai:belongsTo ?model .
  }
  UNION
  {
    ?defs tai:belongsTo ?model .
    ?elem tai:belongsTo ?defs .
  }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?origId ?normId WHERE {
  ?model a bboExt:Model .
  {
    ?model tai:originalId ?origId .
    FILTER(CONTAINS(LCASE(STR(?origId)), "1dccc40d34ef40f9b36123e2fbca1a63"))
  }
  UNION
  {
    ?model tai:normalizedId ?normId .
    FILTER(CONTAINS(LCASE(STR(?normId)), "1dccc40d34ef40f9b36123e2fbca1a63"))
  }
  OPTIONAL { ?model bbo:name ?modelName . }
}
LIMIT 25
